const feed = $json.feed;
if (!feed || !feed.entry) {
  return [];
}

return feed.entry.map(e => {

  // Normalize authors: always array
  const authorsArray = Array.isArray(e.author) ? e.author : [e.author].filter(Boolean);

  const authors = authorsArray
    .map(a => (a.name?._ || a.name || "").trim())
    .join(', ');

  return {
    source: "arXiv",
    title: (e.title?._ || e.title || "").trim(),
    summary: (e.summary?._ || e.summary || "").trim(),
    link: (e.id?._ || e.id || "").trim(),
    pdf: (Array.isArray(e.link) && e.link.find(l => l.title === "pdf")?.href) || "",
    authors
  };
});

// input is an array of models (like your pasted JSON)
const items = $input.all();

// ✅ remove duplicates by modelId
const seen = new Set();

const cleaned = items
  .map(item => item.json)       // extract JSON payload
  .filter(model => {
    if (seen.has(model.modelId)) return false;
    seen.add(model.modelId);
    return true;
  })
  .map(model => {
    return {
      source: "HuggingFace",
      title: model.modelId || model.id || "Unknown model",
      pipeline: model.pipeline_tag || "Unknown pipeline",
      createdAt: model.createdAt || "",
      likes: model.likes || 0,
      downloads: model.downloads || 0,
      summary: (model.tags && model.tags.length > 0)
        ? model.tags.slice(0, 3).join(", ")  // short summary from tags
        : "No summary",
      link: `https://huggingface.co/${model.modelId}`
    };
  });

// ✅ return as proper n8n items
return cleaned.map(c => ({ json: c }));

const items = $input.all();
const results = [];

for (const item of items) {

  // Safely read nested structure
  const content = item.json?.content;
  const parts = content?.parts;

  if (parts && Array.isArray(parts) && parts[0]?.text) {
    results.push({
      summary: parts[0].text.trim()
    });
  }
}

return results.map(r => ({ json: r }));

// Get all items coming in
const input = $items();

// Extract "summary" from each item
const summaries = input.map(i => i.json.summary);

// Combine all into one string
const combined = summaries.join("\n\n----------------------\n\n");

// Return as a single item
return [
  {
    json: {
      emailBody: combined
    }
  }
];

let text = $json.emailBody;

// Convert literal "\n" into real new lines
text = text.replace(/\\n/g, '\n');

// Clean up spacing
text = text.replace(/----------------------/g, '\n---\n');
text = text.replace(/\n{3,}/g, '\n\n');
text = text.replace(/##\s?/g, '\n<h2>');
text = text.replace(/\*\*(.*?)\*\*/g, '<b>$1</b>');
text = text.replace(/^- (.*)$/gm, '<li>$1</li>');
text = text.replace(/\[(.*?)\]\((.*?)\)/g, '<a href="$2">$1</a>');

// Convert lines to <p>
text = text
  .split('\n')
  .map(line => {
    if (line.startsWith('<h2>')) return line + '</h2>';
    if (line.startsWith('<li>')) return line;
    if (line.trim() === '') return '';
    return `<p>${line}</p>`;
  })
  .join('\n');

// Wrap all <li> tags into <ul>
text = text.replace(/(<li>[\s\S]*?<\/li>)/g, '<ul>$1</ul>');

return {
  formattedEmail: text
};
